contracts/Bank.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "./BankConsortium.sol";

contract Bank {
    string public name;
    address public manager;
    BankConsortium public consortium;
    
    mapping(address => bool) public customers;
    address[] public customerList;
    
    event CustomerRegistered(address customer);
    event DepositMade(address customer, uint256 amount);
    event WithdrawalMade(address customer, uint256 amount);
    event ConversionToStable(address customer, uint256 amount);
    event ConversionToTokenized(address customer, uint256 amount);
    
    constructor(string memory _name, address _consortium) {
        name = _name;
        manager = msg.sender;
        consortium = BankConsortium(_consortium);
    }
    
    modifier onlyManager() {
        require(msg.sender == manager, "Only manager can call this");
        _;
    }
    
    modifier onlyCustomer() {
        require(customers[msg.sender], "Only registered customers can call this");
        _;
    }
    
    function registerCustomer(address customer) external onlyManager {
        require(!customers[customer], "Customer already registered");
        customers[customer] = true;
        customerList.push(customer);
        emit CustomerRegistered(customer);
    }
    
    function deposit() external payable onlyCustomer {
        require(msg.value > 0, "Deposit amount must be greater than 0");
        
        // Mint tokenized deposit to customer
        consortium.tokenizedDeposit().bankMint(msg.sender, msg.value);
        
        emit DepositMade(msg.sender, msg.value);
    }
    
    function convertToStableCoin(uint256 amount) external onlyCustomer {
        require(
            consortium.tokenizedDeposit().balanceOf(msg.sender) >= amount,
            "Insufficient tokenized deposit"
        );
        
        bool success = consortium.convertToStableCoin(msg.sender, amount, name);
        require(success, "Conversion failed");
        
        emit ConversionToStable(msg.sender, amount);
    }
    
    function convertToTokenizedDeposit(uint256 amount) external onlyCustomer {
        require(
            consortium.stableCoin().balanceOf(msg.sender) >= amount,
            "Insufficient stable coins"
        );
        
        bool success = consortium.convertToTokenizedDeposit(msg.sender, amount, name);
        require(success, "Conversion failed");
        
        emit ConversionToTokenized(msg.sender, amount);
    }
    
    function intraBankTransfer(address to, uint256 amount) external onlyCustomer {
        require(customers[to], "Recipient must be a customer of this bank");
        consortium.tokenizedDeposit().intraBankTransfer(to, amount);
    }
    
    function withdraw(uint256 amount) external onlyCustomer {
        require(
            consortium.tokenizedDeposit().balanceOf(msg.sender) >= amount,
            "Insufficient tokenized deposit"
        );
        
        // Burn tokenized deposit
        consortium.tokenizedDeposit().bankBurn(msg.sender, amount);
        
        // Transfer ETH to customer
        payable(msg.sender).transfer(amount);
        
        emit WithdrawalMade(msg.sender, amount);
    }
    
    function getCustomerCount() external view returns (uint256) {
        return customerList.length;
    }
    
    function isCustomer(address addr) external view returns (bool) {
        return customers[addr];
    }
    
    // Fallback function to receive ETH
    receive() external payable {}
}

contracts/BankConsortium.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "./Bank.sol";
import "./BankStableCoin.sol";
import "./TokenizedDeposit.sol";

contract BankConsortium {
    address public owner;
    BankStableCoin public stableCoin;
    TokenizedDeposit public tokenizedDeposit;
    
    struct BankInfo {
        address bankAddress;
        string name;
        uint256 reserveAllocation;
        uint256 currentReserve;
        bool isActive;
    }
    
    mapping(string => BankInfo) public banks;
    mapping(address => string) public bankAddressToName;
    string[] public bankNames;
    
    uint256 public totalReservePool;
    
    event BankRegistered(string bankName, address bankAddress, uint256 reserveAllocation);
    event ReserveAllocated(uint256 totalReserve);
    event InterBankTransfer(address from, address to, uint256 amount, string fromBank, string toBank);
    
    constructor() {
        owner = msg.sender;
        stableCoin = new BankStableCoin(address(this));
        tokenizedDeposit = new TokenizedDeposit(address(this));
    }
    
    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can call this");
        _;
    }
    
    modifier onlyBank() {
        require(banks[bankAddressToName[msg.sender]].isActive, "Only registered banks can call this");
        _;
    }
    
    function registerBank(
        string memory bankName,
        address bankAddress,
        uint256 reserveAllocation
    ) external onlyOwner {
        require(banks[bankName].bankAddress == address(0), "Bank already registered");
        
        banks[bankName] = BankInfo({
            bankAddress: bankAddress,
            name: bankName,
            reserveAllocation: reserveAllocation,
            currentReserve: 0,
            isActive: true
        });
        
        bankAddressToName[bankAddress] = bankName;
        bankNames.push(bankName);
        
        emit BankRegistered(bankName, bankAddress, reserveAllocation);
    }
    
    function allocateReservePool(uint256 totalPool) external onlyOwner {
        totalReservePool = totalPool;
        uint256 remaining = totalPool;
        
        for(uint256 i = 0; i < bankNames.length; i++) {
            BankInfo storage bank = banks[bankNames[i]];
            uint256 allocation = (totalPool * bank.reserveAllocation) / 100;
            bank.currentReserve = allocation;
            remaining -= allocation;
        }
        
        if(remaining > 0) {
            banks[bankNames[0]].currentReserve += remaining;
        }
        
        emit ReserveAllocated(totalPool);
    }
    
    function convertToStableCoin(
        address user,
        uint256 amount,
        string memory bankName
    ) external onlyBank returns (bool) {
        BankInfo storage bank = banks[bankName];
        require(bank.currentReserve >= amount, "Insufficient reserve");
        
        // Burn tokenized deposit
        tokenizedDeposit.bankBurn(user, amount);
        
        // Update bank reserve
        bank.currentReserve -= amount;
        
        // Mint stable coin
        stableCoin.mint(user, amount);
        
        return true;
    }
    
    function convertToTokenizedDeposit(
        address user,
        uint256 amount,
        string memory bankName
    ) external onlyBank returns (bool) {
        // Burn stable coin
        stableCoin.burn(user, amount);
        
        // Update bank reserve
        banks[bankName].currentReserve += amount;
        
        // Mint tokenized deposit
        tokenizedDeposit.bankMint(user, amount);
        
        return true;
    }
    
    function processInterBankTransfer(
        address from,
        address to,
        uint256 amount,
        string memory fromBank,
        string memory toBank
    ) external onlyBank {
        // Stable coin should be transferred first by user
        // This function just validates and logs
        emit InterBankTransfer(from, to, amount, fromBank, toBank);
    }
    
    function getBankReserve(string memory bankName) external view returns (uint256) {
        return banks[bankName].currentReserve;
    }
    
    function getTotalReserve() external view returns (uint256) {
        uint256 total = 0;
        for(uint256 i = 0; i < bankNames.length; i++) {
            total += banks[bankNames[i]].currentReserve;
        }
        return total;
    }
}

contracts/BankStableCoin.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";


import "./BankConsortium.sol";

contract BankStableCoin is ERC20, Ownable {
    BankConsortium public consortium;
    
    mapping(address => bool) public banks;
    
    constructor(address _consortium) ERC20("BankStableCoin", "BSC") Ownable(msg.sender) {
        consortium = BankConsortium(_consortium);
    }
    
    modifier onlyBank() {
        require(banks[msg.sender], "Only banks can call this");
        _;
    }
    
    function addBank(address bank) external onlyOwner {
        banks[bank] = true;
    }
    
    function mint(address to, uint256 amount) external onlyBank {
        _mint(to, amount);
    }
    
    function burn(address from, uint256 amount) external onlyBank {
        _burn(from, amount);
    }
    
    function decimals() public pure override returns (uint8) {
        return 2; // 2 decimal places for cents
    }
}

contracts/TokenizedDeposit.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

import "./BankConsortium.sol";

contract TokenizedDeposit is ERC20, Ownable {
    BankConsortium public consortium;
    
    mapping(address => bool) public banks;
    
    event BankMint(address indexed to, uint256 amount);
    event BankBurn(address indexed from, uint256 amount);
    event IntraBankTransfer(address indexed from, address indexed to, uint256 amount);
    
    constructor(address _consortium) ERC20("TokenizedDeposit", "TKD") Ownable(msg.sender) {
        consortium = BankConsortium(_consortium);
    }
    
    modifier onlyBank() {
        require(banks[msg.sender], "Only banks can call this");
        _;
    }
    
    function addBank(address bank) external onlyOwner {
        banks[bank] = true;
    }
    
    function bankMint(address to, uint256 amount) external onlyBank {
        _mint(to, amount);
        emit BankMint(to, amount);
    }
    
    function bankBurn(address from, uint256 amount) external onlyBank {
        _burn(from, amount);
        emit BankBurn(from, amount);
    }
    
    function intraBankTransfer(address to, uint256 amount) external {
        require(balanceOf(msg.sender) >= amount, "Insufficient balance");
        _transfer(msg.sender, to, amount);
        emit IntraBankTransfer(msg.sender, to, amount);
    }
    
    function decimals() public pure override returns (uint8) {
        return 2; // 2 decimal places for cents
    }
}

